INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('df39f8162a7657a686a616bc48758288696fcbd5981a7fb7150f94788e91049e','End Semester','Chemistry','CH24101','3','2025','Q.3(a)','In a temperature-jump experiment, derive the expression for the relaxation time t of a reversible reaction A ⇌ B in terms of the forward and reverse rate constants.','\\text{In a temperature-jump experiment, derive the expression for the relaxation time } \\tau \\text{ of a reversible reaction } A \\xrightleftharpoons[k_r]{k_f} B \\text{ in terms of the forward and reverse rate constants.}','To derive the relaxation time for the reaction A ⇌ B, we assume a first-order reversible reaction with forward rate constant k_f and reverse rate constant k_r. Let [A] and [B] be the concentrations at time t. The rate of change of [A] is given by d[A]/dt = -k_f[A] + k_r[B]. We define deviations from equilibrium concentration as δ[A] = [A] - [A]_eq and δ[B] = [B] - [B]_eq. Since mass is conserved, [A] + [B] = [A]_eq + [B]_eq, implying δ[A] = -δ[B]. Substituting these into the rate equation and noting that at equilibrium d[A]_eq/dt = 0, we obtain d(δ[A])/dt = -(k_f + k_r)δ[A]. Solving this first-order linear differential equation gives δ[A](t) = δ[A](0) * exp(-t/τ), where τ = 1/(k_f + k_r).','Consider the reaction A \\xrightleftharpoons[k_r]{k_f} B. The rate law is: \\frac{d[A]}{dt} = -k_f[A] + k_r[B]. At equilibrium: 0 = -k_f[A]_{eq} + k_r[B]_{eq}. Define the deviation variables: \\delta[A] = [A] - [A]_{eq} and \\delta[B] = [B] - [B]_{eq}. By conservation of mass, [A] + [B] = [A]_{eq} + [B]_{eq}, so \\delta[A] = -\\delta[B]. Substituting these into the rate equation: \\frac{d(\\delta[A] + [A]_{eq})}{dt} = -k_f([A]_{eq} + \\delta[A]) + k_r([B]_{eq} + \\delta[B]). Since \\frac{d[A]_{eq}}{dt} = 0, we get \\frac{d\\delta[A]}{dt} = -k_f[A]_{eq} - k_f\\delta[A] + k_r[B]_{eq} + k_r\\delta[B]. Given k_f[A]_{eq} = k_r[B]_{eq} and \\delta[B] = -\\delta[A]: \\frac{d\\delta[A]}{dt} = -k_f\\delta[A] - k_r\\delta[A] = -(k_f + k_r)\\delta[A]. This is a first-order differential equation of the form \\frac{dx}{dt} = -\\frac{1}{\\tau}x. Comparing terms, we identify the relaxation time \\tau as \\tau = \\frac{1}{k_f + k_r}.','\\tau = \\frac{1}{k_f + k_r}','["Chemical Kinetics", "Relaxation Methods"]','derivation','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('dff0da379c4a1f51409dc3865b2b8e6285b1060854668c5a7a3f87623905a432','End Semester','Chemistry','CH24101','3','2025','Q.3(b)','Derive Michaelis-Menten equation.','\\text{Derive Michaelis-Menten equation.}','To derive the Michaelis-Menten equation, we consider the reaction scheme where enzyme (E) and substrate (S) form an enzyme-substrate complex (ES), which then dissociates into product (P) and free enzyme (E). The assumptions are: (1) The reaction reaches a quasi-steady state where [ES] is constant (Briggs-Haldane assumption), (2) The substrate concentration [S] is much greater than the enzyme concentration [E], and (3) The initial rate is measured, so [P] is negligible. We define the rates using the rate constants k1 (forward), k-1 (reverse), and k2 (catalytic). The rate of change of [ES] is d[ES]/dt = k1[E][S] - (k-1 + k2)[ES] = 0. Substituting [E] = [E]t - [ES] and rearranging leads to the definition of the Michaelis constant Km = (k-1 + k2)/k1. Solving for [ES] and substituting into the velocity expression v = k2[ES] gives the final equation v = Vmax[S] / (Km + [S]).','Reaction Scheme: E + S \\xrightleftharpoons[k_{-1}]{k_{1}} ES \\xrightarrow{k_{2}} E + P. \\\\ \\text{1. Quasi-Steady State Approximation: } \\frac{d[ES]}{dt} = k_{1}[E][S] - (k_{-1} + k_{2})[ES] = 0. \\\\ \\text{2. Total Enzyme Conservation: } [E]_{t} = [E] + [ES] \\implies [E] = [E]_{t} - [ES]. \\\\ \\text{3. Substitute into Rate Equation: } k_{1}([E]_{t} - [ES])[S] = (k_{-1} + k_{2})[ES]. \\\\ \\text{4. Define } K_{m} = \\frac{k_{-1} + k_{2}}{k_{1}}: \\\\ ([E]_{t} - [ES])[S] = K_{m}[ES] \\implies [E]_{t}[S] - [ES][S] = K_{m}[ES]. \\\\ \\text{5. Solve for [ES]: } [ES](K_{m} + [S]) = [E]_{t}[S] \\implies [ES] = \\frac{[E]_{t}[S]}{K_{m} + [S]}. \\\\ \\text{6. Reaction Velocity: } v = k_{2}[ES]. \\\\ \\text{Let } V_{max} = k_{2}[E]_{t}. \\\\ \\text{Result: } v = \\frac{V_{max}[S]}{K_{m} + [S]}.','v = \\frac{V_{max}[S]}{K_m + [S]}','["Biochemistry", "Enzyme Kinetics"]','derivation','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('afce95637fcb1bc7f940f3005793e3c529980255f034cbf14c2d9068686f1869','End Semester','Chemistry','CH24101','3','2024','Q.3(a)','Derive the kinetics of consecutive reaction and show the graphical representation of variation of concentration of A, B, C.','\\text{Derive the kinetics of consecutive reaction } A \\xrightarrow{k_1} B \\xrightarrow{k_2} C \\text{ and show the graphical representation.}','For the consecutive reaction A -> B -> C with rate constants k1 and k2, we assume first-order kinetics for both steps. We start with rate laws: d[A]/dt = -k1[A], d[B]/dt = k1[A] - k2[B], and d[C]/dt = k2[B]. Integrating [A] gives [A] = [A]0 * exp(-k1*t). Substituting this into the rate law for [B] yields a linear first-order differential equation: d[B]/dt + k2[B] = k1[A]0 * exp(-k1*t). Using the integrating factor exp(k2*t), we solve for [B]. Finally, using the mass balance [A]0 = [A] + [B] + [C], we determine [C]. Graphically, [A] decays exponentially, [B] rises to a maximum then decays to zero, and [C] approaches [A]0 asymptotically.','Reaction Scheme: A \\xrightarrow{k_1} B \\xrightarrow{k_2} C. \\text{ Rate laws: } \\frac{d[A]}{dt} = -k_1[A], \\frac{d[B]}{dt} = k_1[A] - k_2[B], \\frac{d[C]}{dt} = k_2[B]. \\text{ Integration of } [A]: [A] = [A]_0 e^{-k_1 t}. \\text{ Substituting into } [B] \\text{ eq: } \\frac{d[B]}{dt} + k_2[B] = k_1[A]_0 e^{-k_1 t}. \\text{ Integrating factor: } e^{k_2 t}. \\frac{d}{dt} ( [B] e^{k_2 t} ) = k_1 [A]_0 e^{(k_2 - k_1) t}. \\text{ Integrating: } [B] e^{k_2 t} = \\frac{k_1 [A]_0}{k_2 - k_1} e^{(k_2 - k_1) t} + I. \\text{ At } t=0, [B]=0 \\implies I = -\\frac{k_1 [A]_0}{k_2 - k_1}. \\text{ Thus, } [B] = \\frac{k_1 [A]_0}{k_2 - k_1} (e^{-k_1 t} - e^{-k_2 t}). \\text{ Using } [C] = [A]_0 - [A] - [B]: [C] = [A]_0 ( 1 - \\frac{k_2}{k_2 - k_1} e^{-k_1 t} + \\frac{k_1}{k_2 - k_1} e^{-k_2 t} ).','[A] = [A]_0 e^{-k_1 t}; [B] = \\frac{k_1 [A]_0}{k_2 - k_1} (e^{-k_1 t} - e^{-k_2 t}); [C] = [A]_0 ( 1 - \\frac{k_2}{k_2 - k_1} e^{-k_1 t} + \\frac{k_1}{k_2 - k_1} e^{-k_2 t} )','["Chemical Kinetics", "Consecutive Reactions"]','derivation','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('1337d28a3e7c1206a9f8bd1a433db528b2f8ccde6fb05bb86c1a1b147cfd13ad','End Semester','Chemistry','CH24101','1','2023','Q.1(a)','Draw Born-Haber cycle for the formation of KCL. What are the applications of Born-Haber cycle?','\\text{Draw Born-Haber cycle for the formation of } KCl \\text{. What are the applications of Born-Haber cycle?}','The Born-Haber cycle is a thermodynamic cycle based on Hess\'s Law, which states that the total enthalpy change for a reaction is the same regardless of the path taken. For the formation of KCl, we relate the standard enthalpy of formation to atomization, ionization energy, electron affinity, and lattice energy. Steps: 1. Sublimation of solid Potassium. 2. Ionization of gaseous Potassium. 3. Dissociation of Chlorine gas. 4. Electron attachment to Chlorine. 5. Formation of the ionic lattice. The applications include: 1. Calculating lattice energies of ionic solids. 2. Determining electron affinities of non-metals. 3. Assessing the stability of ionic compounds. 4. Explaining the theoretical basis of ionic bonding.','The Born-Haber cycle for KCl is governed by Hess\'s Law: \\Delta H_f^\\circ = \\Delta H_{sub}(K) + IE(K) + \\frac{1}{2}BE(Cl_2) + EA(Cl) + U_L(KCl). \\\\ \\text{Steps:} \\\\ 1. K(s) \\to K(g) \\quad (\\Delta H_{sub}) \\\\ 2. K(g) \\to K^+(g) + e^- \\quad (IE) \\\\ 3. \\frac{1}{2}Cl_2(g) \\to Cl(g) \\quad (\\frac{1}{2}BE) \\\\ 4. Cl(g) + e^- \\to Cl^-(g) \\quad (EA) \\\\ 5. K^+(g) + Cl^-(g) \\to KCl(s) \\quad (U_L) \\\\ \\text{Final Expression for Lattice Energy } (U_L): U_L = \\Delta H_f^\\circ - [\\Delta H_{sub} + IE + \\frac{1}{2}BE + EA].','U_L = \\Delta H_f^\\circ - (\\Delta H_{sub} + IE + \\frac{1}{2}BE + EA)','["Born-Haber Cycle", "Chemical Bonding", "Thermodynamics"]','derivation','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);